<header class="app-page-head"><div><p class="eyebrow">Private Sammlung</p><h1><?=e($collection['name'])?></h1><p><?=e($collection['description'])?></p></div><form method="post" action="<?=u('/app/collections/delete')?>" data-confirm="Sammlung wirklich löschen?"><?=$csrf?><input type="hidden" name="collection_id" value="<?=e($collection['id'])?>"><button class="button button-danger" type="submit">Sammlung löschen</button></form></header>
<?php if(empty($collection['items'])):?><div class="empty-state"><h2>Noch leer.</h2><p>Füge einen Snack aus deiner Bibliothek hinzu.</p></div><?php else:?><div class="collection-items"><?php foreach($collection['items'] as $item):?><div><span><?=e(str_pad((string)$item['position'],2,'0',STR_PAD_LEFT))?></span><strong><?=e($item['product_name'])?></strong><div class="collection-item-actions"><a href="<?=u('/app/library?q='.urlencode($item['product_name']))?>">Öffnen</a><form method="post" action="<?=u('/app/collections/remove')?>"><?=$csrf?><input type="hidden" name="collection_id" value="<?=e($collection['id'])?>"><input type="hidden" name="item_id" value="<?=e($item['id'])?>"><button class="link-button" type="submit">Entfernen</button></form></div></div><?php endforeach;?></div><?php endif;?>
<section class="collection-add"><h2>Snack hinzufügen</h2><?php if($entries):?><form method="post" action="<?=u('/app/collections/add')?>" class="inline-form"><?=$csrf?><input type="hidden" name="collection_id" value="<?=e($collection['id'])?>"><select name="product_key" aria-label="Snack wählen"><?php foreach($entries as $entry):?><option value="<?=e($entry['product_key'])?>"><?=e($entry['product_name'])?> · <?=e($entry['overall_rating'])?>/10</option><?php endforeach;?></select><button class="button" type="submit">Hinzufügen</button></form><?php else:?><a href="<?=u('/app/scan')?>">Ersten Snack scannen →</a><?php endif;?></section>
<section class="collection-add"><p class="eyebrow">Optional teilen</p><h2>Widerrufbare Momentaufnahme</h2><p>Der Link enthält nur Namen, Beschreibung und die aktuellen Produktnamen – keine Kontodaten.</p><form method="post" action="<?=u('/app/shares/create')?>"><?=$csrf?><input type="hidden" name="share_type" value="collection"><input type="hidden" name="resource_id" value="<?=e($collection['id'])?>"><button class="button button-secondary" type="submit">Sammlungslink erzeugen</button></form><a href="<?=u('/app/shares')?>">Aktive Freigaben verwalten →</a></section>
